SELECT
FROM pet_profile p LEFT JOIN user u ON p.user_id = u.id
p.status = 1
AND (p.name LIKE CONCAT('%', #{keyword}, '%') OR u.username LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%'))
AND p.type = #{type}
AND p.status = #{status}
ORDER BY p.create_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM pet_profile p LEFT JOIN user u ON p.user_id = u.id
p.status = 1
AND (p.name LIKE CONCAT('%', #{keyword}, '%') OR u.username LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%'))
AND p.type = #{type}
AND p.status = #{status}
